import pytest

def test_pin_change_transitions_state_from_open_to_rate_limited(
    api_client, card_with_reset_limit
):
    card_id = card_with_reset_limit["id"]
    pins = ["1111", "2222", "3333", "4444", "5555"]

    for i, pin in enumerate(pins, start=1):
        r = api_client.patch(f"/cards/{card_id}/pin", json={"pin": pin})
        assert r.status_code == 200, f"Attempt {i} should succeed, got {r.status_code}"

    r_over = api_client.patch(f"/cards/{card_id}/pin", json={"pin": "6666"})
    assert r_over.status_code == 429, (
        f"State should be RATE_LIMITED after 5 changes, got {r_over.status_code}"
    )

import pytest

def test_pin_change_rejected_when_card_does_not_belong_to_caller(
    api_client, other_customers_card
):
    card_id = other_customers_card["id"]
    payload = {"pin": "9999"}

    response = api_client.patch(f"/cards/{card_id}/pin", json=payload)

    assert response.status_code in (403, 404), (
        f"Expected 403 or 404 for unauthorized card access, got {response.status_code}"
    )
